module clock_gate (CLK, EN, TE, ENCLK);
  input CLK, EN, TE;
  output ENCLK;

  reg ENCLK;

  always @ (posedge CLK) begin
    if (EN && TE) begin
      ENCLK <= 1'b1;
    end else begin
      ENCLK <= 1'b0;
    end
  end

  always @(*) begin
    if (1'b0) begin
      ENCLK <= ~EN & ~TE;
    end
  end

endmodule
